<?php namespace App\Http\Controllers\KuBo; use App\Http\Controllers\Controller; use App\Models\CommunityNotification; use App\Models\CommunityPost; use App\Models\CommunityPostReaction; use Illuminate\Http\JsonResponse; use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth;

class ReactionController extends Controller {
    public function toggle(Request $r, CommunityPost $post): JsonResponse { $r->validate(['reaction_type'=>'required|in:love,like,fire,laugh,clap,celebrate']); $u=Auth::user(); $e=CommunityPostReaction::where('post_id',$post->id)->where('user_id',$u->empID)->first(); if($e){if($e->reaction_type===$r->reaction_type){$e->delete();$a='removed';}else{$e->update(['reaction_type'=>$r->reaction_type]);$a='changed';}}else{CommunityPostReaction::create(['post_id'=>$post->id,'user_id'=>$u->empID,'reaction_type'=>$r->reaction_type]);$a='added';if($post->user_id!==$u->empID)CommunityNotification::create(['user_id'=>$post->user_id,'type'=>'reaction','reference_id'=>$post->id,'actor_id'=>$u->empID,'message'=>$u->community_full_name.' reacted with '.CommunityPostReaction::reactionEmojis()[$r->reaction_type].' on your post.']);} $s=CommunityPostReaction::where('post_id',$post->id)->selectRaw('reaction_type,COUNT(*) as c')->groupBy('reaction_type')->pluck('c','reaction_type')->toArray(); $c=CommunityPostReaction::where('post_id',$post->id)->where('user_id',$u->empID)->first(); return response()->json(['success'=>true,'action'=>$a,'total'=>array_sum($s),'summary'=>$s,'current_reaction'=>$c?->reaction_type]); }
}